/// Structured shortcut detail content rendered by native reusable components
/// (`ShortcutContentView`). Replaces the old free-form `markdown_content` blob.
/// Decoding is tolerant: any missing field falls back to empty, so older/partial
/// payloads never fail to load.
struct ShortcutContent: Codable {
    /// One-paragraph plain-text overview.
    let summary: String
    /// The primary invocation, e.g. `gitacp your message`. Optional.
    let usage: String?
    /// Ordered "what it does" steps.
    let whatItDoes: [String]
    /// Named parameters with required flag + description.
    let parameters: [ShortcutParameter]
    /// Freeform note/callout lines (warnings, tips, caveats).
    let notes: [String]
    /// Worked examples: a command plus a short description.
    let examples: [ShortcutExample]
    /// Illustrative terminal output. Optional.
    let sampleOutput: String?

    /// JSON mapping keys matching the remote schema.
    enum CodingKeys: String, CodingKey {
        case summary, usage, notes, parameters, examples
        case whatItDoes = "what_it_does"
        case sampleOutput = "sample_output"
    }

    init(from decoder: Decoder) throws {
        let c = try decoder.container(keyedBy: CodingKeys.self)
        summary = (try? c.decode(String.self, forKey: .summary)) ?? ""
        usage = (try? c.decodeIfPresent(String.self, forKey: .usage)) ?? nil
        whatItDoes = (try? c.decode([String].self, forKey: .whatItDoes)) ?? []
        parameters = (try? c.decode([ShortcutParameter].self, forKey: .parameters)) ?? []
        notes = (try? c.decode([String].self, forKey: .notes)) ?? []
        examples = (try? c.decode([ShortcutExample].self, forKey: .examples)) ?? []
        sampleOutput = (try? c.decodeIfPresent(String.self, forKey: .sampleOutput)) ?? nil
    }

    /// True when there is nothing meaningful to render.
    var isEmpty: Bool {
        summary.isEmpty && usage == nil && whatItDoes.isEmpty &&
        parameters.isEmpty && notes.isEmpty && examples.isEmpty && sampleOutput == nil
    }
}

/// A single named parameter for a shortcut.
struct ShortcutParameter: Codable, Hashable, Identifiable {
    let name: String
    let required: Bool
    let description: String
    var id: String { name }
}

/// A worked example: a command paired with a short description.
struct ShortcutExample: Codable, Hashable, Identifiable {
    let command: String
    let description: String
    var id: String { command }
}

