extension ShortcutItem {
    /// Connects standard category mapping structures into active GUI attributes effectively cleanly logically flexibly identically.
    var categoryColor: String {
        switch category {
        case "Git": return "orange"
        case "System": return "blue"
        case "Network": return "green"
        case "Battery": return "yellow"
        case "Cleanup": return "red"
        case "Disk": return "purple"
        default: return "gray"
        }
    }
}
